package cn.nobeta.dingdong.order.domain;
import java.math.BigDecimal;
public class OrderItem {
    private Long id; private Long orderId; private Long skuId; private String skuCode; private String productTitle; private String productImageUrl; private String specJson; private BigDecimal unitPrice; private Integer quantity; private BigDecimal totalAmount;
    public Long getId(){return id;} public void setId(Long id){this.id=id;} public Long getOrderId(){return orderId;} public void setOrderId(Long orderId){this.orderId=orderId;} public Long getSkuId(){return skuId;} public void setSkuId(Long skuId){this.skuId=skuId;} public String getSkuCode(){return skuCode;} public void setSkuCode(String skuCode){this.skuCode=skuCode;} public String getProductTitle(){return productTitle;} public void setProductTitle(String productTitle){this.productTitle=productTitle;} public String getProductImageUrl(){return productImageUrl;} public void setProductImageUrl(String productImageUrl){this.productImageUrl=productImageUrl;} public String getSpecJson(){return specJson;} public void setSpecJson(String specJson){this.specJson=specJson;} public BigDecimal getUnitPrice(){return unitPrice;} public void setUnitPrice(BigDecimal unitPrice){this.unitPrice=unitPrice;} public Integer getQuantity(){return quantity;} public void setQuantity(Integer quantity){this.quantity=quantity;} public BigDecimal getTotalAmount(){return totalAmount;} public void setTotalAmount(BigDecimal totalAmount){this.totalAmount=totalAmount;}
}
